use std::{
    borrow::Cow,
    collections::{BTreeMap, BTreeSet, HashMap, HashSet},
    fmt,
    path::{Path, PathBuf},
};

use specta::{
    Format, Types,
    datatype::{DataType, Fields, NamedDataType, NamedReference, NamedReferenceType, Reference},
};

use crate::{Error, primitives};

const GENERATED_NOTICE: &str =
    "# This file has been generated by Specta. Do not edit this file manually.";
const IMPORTS: &str = "from __future__ import annotations\n\nimport builtins as _specta_builtins\nimport typing as _specta_typing";

/// Controls how Rust modules are represented in generated Python bindings.
#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
pub enum Layout {
    /// Emits nested Python namespace classes for Rust modules.
    Namespaces,
    /// Emits one Python package (`__init__.py`) per Rust module.
    Files,
    /// Prefixes each type name with its Rust module path in one flat file.
    ModulePrefixedName,
    /// Emits all types in one file, requiring globally unique type names.
    #[default]
    FlatFile,
}

impl fmt::Display for Layout {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{self:?}")
    }
}

/// Python 3.13 type-hint exporter.
#[derive(Debug, Clone)]
#[non_exhaustive]
pub struct Python {
    /// Custom content emitted before the generated-file notice.
    pub header: Cow<'static, str>,
    /// Output layout for generated bindings.
    pub layout: Layout,
    raw: Vec<Cow<'static, str>>,
}

impl Default for Python {
    fn default() -> Self {
        Self {
            header: Cow::Borrowed(""),
            layout: Layout::FlatFile,
            raw: Vec::new(),
        }
    }
}

impl Python {
    /// Creates a Python exporter with default configuration.
    pub fn new() -> Self {
        Self::default()
    }

    /// Configures content emitted at the beginning of every generated file.
    ///
    /// A Python future import follows this header, so the header should contain only comments,
    /// an encoding declaration, or a module docstring.
    pub fn header(mut self, header: impl Into<Cow<'static, str>>) -> Self {
        self.header = header.into();
        self
    }

    /// Configures the output layout.
    pub fn layout(mut self, layout: Layout) -> Self {
        self.layout = layout;
        self
    }

    /// Appends raw Python code after generated type declarations.
    ///
    /// For [`Layout::Files`], raw code is emitted in the root package's `__init__.py`.
    pub fn with_raw(mut self, raw: impl Into<Cow<'static, str>>) -> Self {
        self.raw.push(raw.into());
        self
    }

    /// Exports all types into a string.
    ///
    /// [`Layout::Files`] requires [`Self::export_to`] because it creates multiple files.
    pub fn export(&self, types: &Types, format: impl Format) -> Result<String, Error> {
        if self.layout == Layout::Files {
            return Err(Error::unsupported_layout(Layout::Files, "Python::export"));
        }
        let types = format_types(types, &format)?;
        validate_names(self, types.as_ref())?;

        let mut out = render_file_header(self);
        match self.layout {
            Layout::Namespaces => render_namespaces(&mut out, self, types.as_ref())?,
            Layout::FlatFile | Layout::ModulePrefixedName => {
                let body = primitives::export(
                    self,
                    types.as_ref(),
                    types.as_ref().into_sorted_iter(),
                    "",
                )?;
                append_section(&mut out, &body);
            }
            Layout::Files => unreachable!("files layout was rejected above"),
        }
        append_raw(&mut out, &self.raw);
        Ok(out)
    }

    /// Exports types to a file, or to a directory when using [`Layout::Files`].
    pub fn export_to(
        &self,
        path: impl AsRef<Path>,
        types: &Types,
        format: impl Format,
    ) -> Result<(), Error> {
        let path = path.as_ref();
        if self.layout != Layout::Files {
            let output = self.export(types, format)?;
            if let Some(parent) = path.parent() {
                std::fs::create_dir_all(parent)
                    .map_err(|source| Error::create_dir(parent.to_path_buf(), source))?;
            }
            return std::fs::write(path, output)
                .map_err(|source| Error::write_file(path.to_path_buf(), source));
        }

        let types = format_types(types, &format)?;
        validate_names(self, types.as_ref())?;
        export_files(self, path, types.as_ref())
    }
}

impl AsRef<Python> for Python {
    fn as_ref(&self) -> &Python {
        self
    }
}

impl AsMut<Python> for Python {
    fn as_mut(&mut self) -> &mut Python {
        self
    }
}

fn render_file_header(exporter: &Python) -> String {
    let mut out = String::new();
    if !exporter.header.is_empty() {
        out.push_str(exporter.header.trim_end());
        out.push('\n');
    }
    out.push_str(GENERATED_NOTICE);
    out.push_str("\n\n");
    out.push_str(IMPORTS);
    out.push('\n');
    out
}

fn append_section(out: &mut String, section: &str) {
    if section.trim().is_empty() {
        return;
    }
    if !out.ends_with("\n\n") {
        out.push('\n');
    }
    out.push_str(section.trim_end());
    out.push('\n');
}

fn append_raw(out: &mut String, snippets: &[Cow<'static, str>]) {
    for snippet in snippets.iter().filter(|snippet| !snippet.trim().is_empty()) {
        append_section(out, snippet);
    }
}

fn validate_names(exporter: &Python, types: &Types) -> Result<(), Error> {
    let mut seen = HashMap::<String, String>::new();
    if matches!(exporter.layout, Layout::Namespaces | Layout::Files) {
        for ndt in types.into_sorted_iter().filter(|ndt| ndt.ty.is_some()) {
            let segments = ndt
                .module_path
                .split("::")
                .filter(|segment| !segment.is_empty())
                .collect::<Vec<_>>();
            for index in 0..segments.len() {
                let parent = segments[..index]
                    .iter()
                    .map(|segment| primitives::normalized_identifier(segment))
                    .collect::<Vec<_>>()
                    .join("::");
                let child = primitives::normalized_identifier(segments[index]);
                let key = format!("{parent}::{child}");
                let module = format!("module {}", segments[..=index].join("::"));
                if let Some(first) = seen.get(&key) {
                    if first != &module {
                        return Err(
                            Error::duplicate_name(child, first, module).with_named_datatype(ndt)
                        );
                    }
                } else {
                    seen.insert(key, module);
                }
            }
        }
    }
    for ndt in types.into_sorted_iter().filter(|ndt| ndt.ty.is_some()) {
        let exported = primitives::exported_type_name(exporter, ndt);
        let rust_path = rust_type_path(ndt);
        primitives::validate_identifier(&exported, &rust_path)
            .map_err(|error| error.with_named_datatype(ndt))?;
        if exporter.layout == Layout::Namespaces && primitives::is_dunder_mangled(&exported) {
            return Err(Error::invalid_name(rust_path.clone(), exported).with_named_datatype(ndt));
        }
        if matches!(exporter.layout, Layout::Namespaces | Layout::Files) {
            for segment in ndt
                .module_path
                .split("::")
                .filter(|segment| !segment.is_empty())
            {
                primitives::validate_identifier(segment, &rust_path)
                    .map_err(|error| error.with_named_datatype(ndt))?;
                if exporter.layout == Layout::Namespaces && primitives::is_dunder_mangled(segment) {
                    return Err(
                        Error::invalid_name(rust_path.clone(), segment).with_named_datatype(ndt)
                    );
                }
            }
        }
        let collision_key = match exporter.layout {
            Layout::FlatFile | Layout::ModulePrefixedName => {
                primitives::normalized_identifier(&exported)
            }
            Layout::Namespaces | Layout::Files => {
                format!(
                    "{}::{}",
                    ndt.module_path
                        .split("::")
                        .map(primitives::normalized_identifier)
                        .collect::<Vec<_>>()
                        .join("::"),
                    primitives::normalized_identifier(&exported)
                )
            }
        };
        if let Some(first) = seen.insert(collision_key, rust_path.clone()) {
            return Err(Error::duplicate_name(exported, first, rust_path).with_named_datatype(ndt));
        }
    }
    Ok(())
}

fn rust_type_path(ndt: &NamedDataType) -> String {
    if ndt.module_path.is_empty() {
        ndt.name.to_string()
    } else {
        format!("{}::{}", ndt.module_path, ndt.name)
    }
}

#[derive(Default)]
struct Namespace<'a> {
    types: Vec<&'a NamedDataType>,
    children: BTreeMap<&'a str, Namespace<'a>>,
}

fn render_namespaces(out: &mut String, exporter: &Python, types: &Types) -> Result<(), Error> {
    let mut root = Namespace::default();
    for ndt in types.into_sorted_iter().filter(|ndt| ndt.ty.is_some()) {
        let mut namespace = &mut root;
        for segment in ndt
            .module_path
            .split("::")
            .filter(|segment| !segment.is_empty())
        {
            namespace = namespace.children.entry(segment).or_default();
        }
        namespace.types.push(ndt);
    }

    let root_types = root.types.iter().copied();
    let body = primitives::export(exporter, types, root_types, "")?;
    append_section(out, &body);
    for (name, namespace) in root.children {
        let mut body = String::new();
        render_namespace_node(&mut body, exporter, types, name, namespace, "")?;
        append_section(out, &body);
    }
    Ok(())
}

fn render_namespace_node(
    out: &mut String,
    exporter: &Python,
    types: &Types,
    name: &str,
    namespace: Namespace<'_>,
    indent: &str,
) -> Result<(), Error> {
    out.push_str(indent);
    out.push_str("class ");
    out.push_str(name);
    out.push_str(":\n");
    let child_indent = format!("{indent}    ");
    let mut has_body = false;
    for ndt in namespace.types {
        let declaration = primitives::export_named(
            primitives::RenderContext {
                exporter,
                types,
                current_module: &ndt.module_path,
            },
            ndt,
            &child_indent,
        )?;
        if !declaration.is_empty() {
            if has_body {
                out.push('\n');
            }
            out.push_str(&declaration);
            has_body = true;
        }
    }
    for (child_name, child) in namespace.children {
        if has_body {
            out.push('\n');
        }
        render_namespace_node(out, exporter, types, child_name, child, &child_indent)?;
        has_body = true;
    }
    if !has_body {
        out.push_str(&child_indent);
        out.push_str("pass\n");
    }
    Ok(())
}

fn export_files(exporter: &Python, root: &Path, types: &Types) -> Result<(), Error> {
    let mut modules = BTreeMap::<String, Vec<&NamedDataType>>::new();
    for ndt in types.into_sorted_iter().filter(|ndt| ndt.ty.is_some()) {
        modules
            .entry(ndt.module_path.to_string())
            .or_default()
            .push(ndt);
    }
    let module_names = modules.keys().cloned().collect::<Vec<_>>();
    modules.entry(String::new()).or_default();
    for module in module_names {
        let mut parent = String::new();
        for segment in module.split("::").filter(|segment| !segment.is_empty()) {
            if !parent.is_empty() {
                parent.push_str("::");
            }
            parent.push_str(segment);
            modules.entry(parent.clone()).or_default();
        }
    }

    let old_files = collect_generated_files(root)?;
    let mut generated = HashSet::new();
    for (module, ndts) in modules {
        let path = module_file(root, &module);
        ensure_no_symlink_components(root, &path)?;
        if !generated.insert(path.clone()) {
            let first = ndts.first().map_or("<unknown>", |ndt| ndt.name.as_ref());
            return Err(Error::duplicate_file(path, first, first));
        }
        let mut out = render_file_header(exporter);
        let imports = module_imports(types, &module, &ndts);
        if !imports.is_empty() {
            out.push_str("\nif _specta_typing.TYPE_CHECKING:\n");
            for import in &imports {
                out.push_str("    ");
                out.push_str(import);
                out.push('\n');
            }
        }
        for ndt in ndts {
            let declaration = primitives::export_named(
                primitives::RenderContext {
                    exporter,
                    types,
                    current_module: &module,
                },
                ndt,
                "",
            )?;
            append_section(&mut out, &declaration);
        }
        if !imports.is_empty() {
            append_section(
                &mut out,
                &imports.into_iter().collect::<Vec<_>>().join("\n"),
            );
        }
        if module.is_empty() {
            append_raw(&mut out, &exporter.raw);
        }
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)
                .map_err(|source| Error::create_dir(parent.to_path_buf(), source))?;
        }
        std::fs::write(&path, out).map_err(|source| Error::write_file(path.clone(), source))?;
    }

    let stale_directories = old_files
        .difference(&generated)
        .filter_map(|path| path.parent().map(Path::to_path_buf))
        .collect::<Vec<_>>();
    for stale in old_files.difference(&generated) {
        std::fs::remove_file(stale).map_err(|source| Error::write_file(stale.clone(), source))?;
    }
    for directory in stale_directories {
        remove_empty_ancestors(directory, root)?;
    }
    Ok(())
}

fn module_file(root: &Path, module: &str) -> PathBuf {
    module
        .split("::")
        .filter(|segment| !segment.is_empty())
        .map(primitives::normalized_identifier)
        .fold(root.to_path_buf(), |path, segment| path.join(segment))
        .join("__init__.py")
}

fn ensure_no_symlink_components(root: &Path, path: &Path) -> Result<(), Error> {
    for ancestor in root.ancestors() {
        match std::fs::symlink_metadata(ancestor) {
            Ok(metadata) if metadata.file_type().is_symlink() => {
                return Err(Error::symlink_escape(ancestor.to_path_buf()));
            }
            Ok(_) => {}
            Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
            Err(source) => return Err(Error::create_dir(ancestor.to_path_buf(), source)),
        }
    }

    let mut current = root.to_path_buf();
    let relative = path.strip_prefix(root).unwrap_or(path);
    for component in relative.components() {
        current.push(component);
        match std::fs::symlink_metadata(&current) {
            Ok(metadata) if metadata.file_type().is_symlink() => {
                return Err(Error::symlink_escape(current));
            }
            Ok(_) => {}
            Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
            Err(source) => return Err(Error::create_dir(current, source)),
        }
    }
    Ok(())
}

fn module_imports(types: &Types, current: &str, ndts: &[&NamedDataType]) -> BTreeSet<String> {
    let mut references = BTreeSet::<(String, String)>::new();
    let mut visiting = HashSet::new();
    for ndt in ndts {
        for generic in ndt.generics.iter() {
            if let Some(default) = &generic.default {
                collect_referenced_types(types, default, &mut references, &mut visiting);
            }
        }
        if let Some(ty) = &ndt.ty {
            collect_referenced_types(types, ty, &mut references, &mut visiting);
        }
    }

    let current_segments = split_module(current);
    let mut imports = BTreeSet::new();
    for (target_module, target_name) in references {
        if target_module == current {
            continue;
        }
        let target_segments = split_module(&target_module);
        let common = current_segments
            .iter()
            .zip(&target_segments)
            .take_while(|(left, right)| left == right)
            .count();
        let dots = ".".repeat(current_segments.len() - common + 1);
        let remaining_module = target_segments[common..].join(".");
        let alias = primitives::file_import_alias(&target_module, &target_name);
        let from = if remaining_module.is_empty() {
            dots
        } else {
            format!("{dots}{remaining_module}")
        };
        imports.insert(format!("from {from} import {target_name} as {alias}"));
    }
    imports
}

fn split_module(module: &str) -> Vec<String> {
    module
        .split("::")
        .filter(|segment| !segment.is_empty())
        .map(primitives::normalized_identifier)
        .collect()
}

fn collect_referenced_types(
    types: &Types,
    datatype: &DataType,
    references: &mut BTreeSet<(String, String)>,
    visiting: &mut HashSet<NamedReference>,
) {
    match datatype {
        DataType::List(list) => collect_referenced_types(types, &list.ty, references, visiting),
        DataType::Map(map) => {
            collect_referenced_types(types, map.key_ty(), references, visiting);
            collect_referenced_types(types, map.value_ty(), references, visiting);
        }
        DataType::Struct(strct) => {
            collect_fields_references(types, &strct.fields, references, visiting)
        }
        DataType::Enum(enm) => {
            for (_, variant) in &enm.variants {
                collect_fields_references(types, &variant.fields, references, visiting);
            }
        }
        DataType::Tuple(tuple) => {
            for element in &tuple.elements {
                collect_referenced_types(types, element, references, visiting);
            }
        }
        DataType::Nullable(inner) => collect_referenced_types(types, inner, references, visiting),
        DataType::Intersection(parts) => {
            for part in parts {
                collect_referenced_types(types, part, references, visiting);
            }
        }
        DataType::Reference(Reference::Named(reference)) => match &reference.inner {
            NamedReferenceType::Reference { generics, .. } => {
                if let Some(ndt) = types.get(reference) {
                    references.insert((ndt.module_path.to_string(), ndt.name.to_string()));
                    if visiting.insert(reference.clone()) {
                        if let Some(datatype) = &ndt.ty {
                            collect_referenced_types(types, datatype, references, visiting);
                        }
                        visiting.remove(reference);
                    }

                    let mut scoped = Vec::new();
                    let mut resolved_arguments = Vec::new();
                    let mut all_default = true;
                    for definition in ndt.generics.iter() {
                        let explicit = generics
                            .iter()
                            .find(|(generic, _)| generic == &definition.reference())
                            .map(|(_, datatype)| datatype.clone());
                        let default = definition.default.as_ref().map(|default| {
                            let mut default = default.clone();
                            primitives::substitute_generics(&mut default, &scoped);
                            default
                        });
                        let resolved = explicit.or_else(|| default.clone()).unwrap_or_else(|| {
                            DataType::Reference(Reference::opaque(crate::opaque::Unknown))
                        });
                        all_default &= default.as_ref().is_some_and(|default| default == &resolved);
                        scoped.push((definition.reference(), resolved.clone()));
                        resolved_arguments.push(resolved);
                    }
                    if !all_default {
                        for argument in &resolved_arguments {
                            collect_referenced_types(types, argument, references, visiting);
                        }
                    }
                } else {
                    for (_, generic) in generics {
                        collect_referenced_types(types, generic, references, visiting);
                    }
                }
            }
            NamedReferenceType::Inline { dt, .. } => {
                collect_referenced_types(types, dt, references, visiting)
            }
            NamedReferenceType::Recursive(_) => {}
        },
        DataType::Primitive(_)
        | DataType::Generic(_)
        | DataType::Reference(Reference::Opaque(_)) => {}
    }
}

fn collect_fields_references(
    types: &Types,
    fields: &Fields,
    references: &mut BTreeSet<(String, String)>,
    visiting: &mut HashSet<NamedReference>,
) {
    match fields {
        Fields::Unit => {}
        Fields::Unnamed(fields) => {
            for field in &fields.fields {
                if let Some(ty) = &field.ty {
                    collect_referenced_types(types, ty, references, visiting);
                }
            }
        }
        Fields::Named(fields) => {
            for (_, field) in &fields.fields {
                if let Some(ty) = &field.ty {
                    collect_referenced_types(types, ty, references, visiting);
                }
            }
        }
    }
}

fn collect_generated_files(root: &Path) -> Result<HashSet<PathBuf>, Error> {
    fn visit(path: &Path, files: &mut HashSet<PathBuf>) -> Result<(), Error> {
        let entries = match std::fs::read_dir(path) {
            Ok(entries) => entries,
            Err(error) if error.kind() == std::io::ErrorKind::NotFound => return Ok(()),
            Err(source) => return Err(Error::create_dir(path.to_path_buf(), source)),
        };
        for entry in entries {
            let entry = entry.map_err(|source| Error::create_dir(path.to_path_buf(), source))?;
            let entry_path = entry.path();
            let file_type = entry
                .file_type()
                .map_err(|source| Error::create_dir(entry_path.clone(), source))?;
            if file_type.is_symlink() {
                continue;
            }
            if file_type.is_dir() {
                visit(&entry_path, files)?;
            } else if entry_path
                .file_name()
                .is_some_and(|name| name == "__init__.py")
                && std::fs::read_to_string(&entry_path)
                    .is_ok_and(|contents| contents.contains(GENERATED_NOTICE))
            {
                files.insert(entry_path);
            }
        }
        Ok(())
    }
    let mut files = HashSet::new();
    visit(root, &mut files)?;
    Ok(files)
}

fn remove_empty_ancestors(mut path: PathBuf, root: &Path) -> Result<(), Error> {
    while path != root && path.starts_with(root) {
        match std::fs::read_dir(&path) {
            Ok(mut entries) => {
                if entries.next().is_some() {
                    break;
                }
                std::fs::remove_dir(&path)
                    .map_err(|source| Error::create_dir(path.clone(), source))?;
            }
            Err(error) if error.kind() == std::io::ErrorKind::NotFound => {}
            Err(source) => return Err(Error::create_dir(path, source)),
        }
        let Some(parent) = path.parent() else {
            break;
        };
        path = parent.to_path_buf();
    }
    Ok(())
}

fn format_types<'a>(types: &'a Types, format: &dyn Format) -> Result<Cow<'a, Types>, Error> {
    let mapped = match format
        .map_types(types)
        .map_err(|source| Error::format("type graph formatter failed", source))?
    {
        Cow::Borrowed(_) => types.clone(),
        Cow::Owned(types) => types,
    };
    let source_types = mapped.clone();
    let mut output = mapped;
    let mut error = None;
    output.iter_mut(|ndt| {
        if error.is_some() {
            return;
        }
        let path = vec![Cow::Owned(rust_type_path(ndt))];
        for generic in ndt.generics.to_mut() {
            let Some(default) = generic.default.clone() else {
                continue;
            };
            let mut generic_path = path.clone();
            generic_path.push(Cow::Owned(format!("<generic_default:{}>", generic.name)));
            match map_datatype(format, &source_types, &default, &generic_path) {
                Ok(default) => generic.default = Some(default),
                Err(source) => {
                    error = Some(source.with_named_datatype(ndt));
                    return;
                }
            }
        }
        let Some(datatype) = ndt.ty.clone() else {
            return;
        };
        match map_datatype(format, &source_types, &datatype, &path) {
            Ok(datatype) => ndt.ty = Some(datatype),
            Err(source) => error = Some(source.with_named_datatype(ndt)),
        }
    });
    if let Some(error) = error {
        Err(error)
    } else {
        Ok(Cow::Owned(output))
    }
}

fn map_datatype(
    format: &dyn Format,
    types: &Types,
    datatype: &DataType,
    path: &[Cow<'static, str>],
) -> Result<DataType, Error> {
    if matches!(datatype, DataType::Generic(_)) {
        return Ok(datatype.clone());
    }
    let mapped = match format.map_type(types, datatype) {
        Ok(mapped) => mapped.into_owned(),
        Err(source) if source.to_string().contains("Unresolved generic reference") => {
            datatype.clone()
        }
        Err(source) => {
            return Err(Error::format_at(
                "datatype formatter failed",
                path.iter().map(Cow::as_ref).collect::<Vec<_>>().join("."),
                source,
            ));
        }
    };
    map_datatype_children(format, types, mapped, path)
}

fn map_datatype_children(
    format: &dyn Format,
    types: &Types,
    mut datatype: DataType,
    path: &[Cow<'static, str>],
) -> Result<DataType, Error> {
    let child_path = |segment: Cow<'static, str>| {
        let mut path = path.to_vec();
        path.push(segment);
        path
    };
    match &mut datatype {
        DataType::Primitive(_)
        | DataType::Generic(_)
        | DataType::Reference(Reference::Opaque(_)) => {}
        DataType::List(list) => {
            *list.ty = map_datatype(format, types, &list.ty, &child_path("<list_item>".into()))?;
        }
        DataType::Map(map) => {
            let key = map_datatype(format, types, map.key_ty(), &child_path("<map_key>".into()))?;
            let value = map_datatype(
                format,
                types,
                map.value_ty(),
                &child_path("<map_value>".into()),
            )?;
            map.set_key_ty(key);
            map.set_value_ty(value);
        }
        DataType::Struct(strct) => map_fields(format, types, &mut strct.fields, path)?,
        DataType::Enum(enm) => {
            for (name, variant) in &mut enm.variants {
                map_fields(
                    format,
                    types,
                    &mut variant.fields,
                    &child_path(name.clone()),
                )?;
            }
        }
        DataType::Tuple(tuple) => {
            for (index, element) in tuple.elements.iter_mut().enumerate() {
                *element = map_datatype(
                    format,
                    types,
                    element,
                    &child_path(index.to_string().into()),
                )?;
            }
        }
        DataType::Nullable(inner) => **inner = map_datatype(format, types, inner, path)?,
        DataType::Intersection(parts) => {
            for part in parts {
                *part = map_datatype(format, types, part, path)?;
            }
        }
        DataType::Reference(Reference::Named(reference)) => match &mut reference.inner {
            NamedReferenceType::Reference { generics, .. } => {
                for (_, generic) in generics {
                    *generic = map_datatype(format, types, generic, path)?;
                }
            }
            NamedReferenceType::Inline { dt, .. } => {
                **dt = map_datatype(format, types, dt, path)?;
            }
            NamedReferenceType::Recursive(_) => {}
        },
    }
    Ok(datatype)
}

fn map_fields(
    format: &dyn Format,
    types: &Types,
    fields: &mut Fields,
    path: &[Cow<'static, str>],
) -> Result<(), Error> {
    match fields {
        Fields::Unit => {}
        Fields::Unnamed(fields) => {
            for (index, field) in fields.fields.iter_mut().enumerate() {
                if let Some(datatype) = &mut field.ty {
                    let mut field_path = path.to_vec();
                    field_path.push(index.to_string().into());
                    *datatype = map_datatype(format, types, datatype, &field_path)?;
                }
            }
        }
        Fields::Named(fields) => {
            for (name, field) in &mut fields.fields {
                if let Some(datatype) = &mut field.ty {
                    let mut field_path = path.to_vec();
                    field_path.push(name.clone());
                    *datatype = map_datatype(format, types, datatype, &field_path)?;
                }
            }
        }
    }
    Ok(())
}
